static id WBParsedJSONObjectFromJSONString(NSString *jsonString) {
    if (![jsonString isKindOfClass:NSString.class] || jsonString.length == 0) {
        return nil;
    }
    NSData *data = [jsonString dataUsingEncoding:NSUTF8StringEncoding];
    if (data.length == 0) {
        return nil;
    }
    return [NSJSONSerialization JSONObjectWithData:data options:NSJSONReadingFragmentsAllowed error:nil];
}

@implementation WBNetworkManager

- (void)reportEventsSync:(NSNumber *)type withData:(nullable NSString *)json time:(NSNumber *)time callback:(WBNetworkBaseCallback)callback {
    NSDictionary *params = nil;
    if (json) {
        params = @{
            @"type": type,
            @"time": time,
            @"data": json
        };
    } else {
        params = @{
            @"type": type,
            @"time": time,
        };
    }
    NSString *traceId = NSUUID.UUID.UUIDString ?: @"";
    NSMutableDictionary *requestExtraFields = [NSMutableDictionary dictionaryWithDictionary:@{
        @"traceId": traceId,
        @"requestType": type ?: @(0),
        @"requestTime": time ?: @(0),
        @"requestParams": params ?: @{}
    }];
    id parsedRequestData = WBParsedJSONObjectFromJSONString(json);
    if (parsedRequestData) {
        requestExtraFields[@"requestDataParsed"] = parsedRequestData;
    }
    [self POST:@"app/event" params:params callback:^(id  _Nullable responseJSON, NSError * _Nullable error) {
        NSMutableDictionary *responseExtraFields = [NSMutableDictionary dictionaryWithDictionary:@{
            @"traceId": traceId,
            @"requestType": type ?: @(0),
            @"requestTime": time ?: @(0),
            @"success": @(error == nil)
        }];
        if (responseJSON) {
            responseExtraFields[@"responseData"] = responseJSON;
        }
        if (error) {
            responseExtraFields[@"error"] = @{
                @"domain": error.domain ?: @"",
                @"code": @(error.code),
                @"description": error.localizedDescription ?: @""
            };
        }
        if (callback) {
            callback(responseJSON, error);
        }
    }];
//    [self POST:@"app/event" params:params callback:callback];
}

- (void)uploadLagEventFileURL:(NSURL *)fileURL callback:(WBNetworkBaseCallback)callback {
    if (!fileURL) {
        if (callback) {
            callback(nil, [NSError errorWithDomain:@"WBNetworkManagerErrorDomain" code:-1 userInfo:@{NSLocalizedDescriptionKey: @"lag event file url is nil"}]);
        }
        return;
    }
    NSMutableDictionary *params = [NSMutableDictionary dictionary];
    params[@"file"] = fileURL;
    [self multipartRequest:@"app/lagLog" params:params callback:callback];
}

