- (void)sendFeedbackWithContent:(NSString * _Nullable)content imageURL:(NSURL * _Nullable)imageURL callback:(WBFeedbackListCallback)callback {
    NSString *url = @"support/send";
    // POST normally when no image needs to be uploaded.
    if (imageURL == nil) {
        NSAssert(content, @"request needs parameter");
        NSDictionary *params = @{
            @"content" : content,
        };
        [self requestFeedbackListCallbackInterfaceWithURL:url params:params callback:callback];
        return;
    }
    // Use multipart request when need to upload image.
    NSMutableDictionary *params = [NSMutableDictionary dictionary];
    params[@"image"] = imageURL;
    if (content) {
        params[@"content"] = content;
    }
    [self requestMultipartFeedbackListCallbackInterfaceWithURL:url params:params callback:callback];
}

