#import "WBGroSplashAd.h"
#import <BUAdSDK/BUAdSDK.h>
#import "WBAppManager.h"
#import "WBGroMoreAdManager.h"

@interface WBGroSplashAd () <BUSplashAdDelegate>

@property (nonatomic, strong) BUSplashAd *splashAd;
@property (nonatomic, strong) dispatch_source_t timeoutTimer;   // 超时计时器
@property (nonatomic, assign) BOOL hasReceivedCallback;         // 是否收到回调
@property (nonatomic, assign) BOOL isTimedOut;                  // 是否超时

@end


@implementation WBGroSplashAd

+ (instancetype)sharedManager {
    static id instance;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        instance = [[WBGroSplashAd alloc] init];
    });
    return instance;
}


#pragma mark - 广告加载与超时控制

/******** 开屏广告配置 *********/
- (void)loadSplashAd {
    BUAdSlot *slot = [[BUAdSlot alloc] init];
    slot.ID = [WBSettingManager sharedManager].splashSlotId; // 聚合广告位ID
    BUSplashAd *splashAd = [[BUSplashAd alloc] initWithSlot:slot adSize:[UIScreen mainScreen].bounds.size];
    splashAd.delegate = self;   // 广告代理
    self.splashAd = splashAd;
    [self.splashAd loadAdData]; // 加载广告数据

    _isTimedOut = NO;
    _hasReceivedCallback = NO;  // 重置状态

    // 启动2秒超时检测
    __weak typeof(self) weakSelf = self;
    dispatch_queue_t queue = dispatch_get_main_queue();
    _timeoutTimer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, queue);
    dispatch_source_set_timer(_timeoutTimer, dispatch_time(DISPATCH_TIME_NOW, 2*NSEC_PER_SEC), DISPATCH_TIME_FOREVER, 0);
    dispatch_source_set_event_handler(_timeoutTimer, ^{
        [weakSelf handleSplashTimeout];
    });
    dispatch_resume(_timeoutTimer);
}

// 超时处理
- (void)handleSplashTimeout {
    if (_hasReceivedCallback || _isTimedOut) return;
    _isTimedOut = YES;
    [self safeDestroySplashAd]; // 统一销毁入口
}


#pragma mark - 安全销毁核心方法

- (void)safeDestroySplashAd {
    // 取消计时器
    if (_timeoutTimer) {
        dispatch_source_cancel(_timeoutTimer);
        _timeoutTimer = nil;
    }

    // 发送开屏广告关闭通知
    [[NSNotificationCenter defaultCenter] postNotificationName:WBSplashAdCloseNotification object:nil];

    // 销毁广告对象
    if (self.splashAd) {
        self.splashAd.delegate = nil; // 解除委托防野指针，防止回调触发已释放对象
        [self.splashAd.mediation destoryAd];
        self.splashAd = nil;
    }

    // 重置状态
    _isTimedOut = NO;
    _hasReceivedCallback = NO;

    // 更新全局广告状态
    [WBGroMoreAdManager sharedManager].hasPresentingScreenAd = NO;
}


#pragma mark - 回调统一处理

- (void)markCallbackReceived {
    if (!_isTimedOut) {
        _hasReceivedCallback = YES;
    }
    if (_timeoutTimer) {
        dispatch_source_cancel(_timeoutTimer); // 确保任何回调都能取消计时器
        _timeoutTimer = nil;
    }
}


#pragma mark - BUMSplashAdDelegate

/******** 开屏广告回调处理 *********/

// 加载成功
- (void)splashAdLoadSuccess:(nonnull BUSplashAd *)splashAd {
    [self markCallbackReceived];
    [WBEventManager logAppAdSplashLoadEvent:@"0"];

    UIViewController * rootVC = [WBAppManager getUIApplicationRootViewController];
    [splashAd showSplashViewInRootViewController:rootVC]; // 将广告内容展示在rootViewController上
}

// 加载失败
- (void)splashAdLoadFail:(nonnull BUSplashAd *)splashAd error:(BUAdError * _Nullable)error {
    [self markCallbackReceived];
    [WBEventManager logAppAdSplashLoadEvent:error.localizedDescription];
    [self safeDestroySplashAd]; // 直接触发安全销毁
}

// 广告即将展示
- (void)splashAdWillShow:(nonnull BUSplashAd *)splashAd {
    [self markCallbackReceived];
    [WBEventManager logAppAdSplashShowEvent:@"0"];
}

// 广告已经展示
- (void)splashAdDidShow:(BUSplashAd *)splashAd {
    [self markCallbackReceived];
    [WBGroMoreAdManager sharedManager].hasPresentingScreenAd = TRUE;
}

// 广告被点击
- (void)splashAdDidClick:(nonnull BUSplashAd *)splashAd {
    [self markCallbackReceived];
}

// 广告视图被关闭
- (void)splashAdDidClose:(BUSplashAd *)splashAd closeType:(BUSplashAdCloseType)closeType {
    [self markCallbackReceived];
    if (closeType != BUSplashAdCloseType_ClickAd) {
        [self safeDestroySplashAd]; // 非点击广告的关闭直接销毁
    }
}

// 广告展示失败
- (void)splashAdDidShowFailed:(BUSplashAd *_Nonnull)splashAd error:(NSError *)error {
    [self markCallbackReceived];
    [WBEventManager logAppAdSplashShowEvent:error.localizedDescription];
    [self safeDestroySplashAd];
}

// 用户与广告进行交互并导致其他控制器关闭时
- (void)splashDidCloseOtherController:(BUSplashAd *)splashAd interactionType:(BUInteractionType)interactionType {
    [self markCallbackReceived];
    [self safeDestroySplashAd];
}

// 开屏广告视图控制器关闭时
- (void)splashAdViewControllerDidClose:(BUSplashAd *)splashAd {
    [self markCallbackReceived];
    [self safeDestroySplashAd];
}

- (void)splashAdRenderFail:(nonnull BUSplashAd *)splashAd error:(BUAdError * _Nullable)error { 
    [self markCallbackReceived];
    [self safeDestroySplashAd];
}


- (void)splashAdRenderSuccess:(nonnull BUSplashAd *)splashAd { 
    [self markCallbackReceived];
}


- (void)splashVideoAdDidPlayFinish:(nonnull BUSplashAd *)splashAd didFailWithError:(NSError * _Nullable)error { 
    [self markCallbackReceived];
    [self safeDestroySplashAd];
}


@end

