@implementation WBNetworkManager (Apppage)

- (void)apppage_launch:(ApppageCallback)callback {
    [self apppage:@"launch" callback:callback];
}

- (void)apppage_splash:(ApppageCallback)callback {
    [self apppage:@"splash" callback:callback];
}

- (void)apppage_discovery:(ApppageCallback)callback {
    [self apppage:@"discovery" callback:callback];
}

- (void)apppage:(NSString *)URI callback:(ApppageCallback)callback {
    NSString *context = @"apppage";
    NSString *URL = [context stringByAppendingPathComponent:URI];
    [self POST:URL params:@{} callback:^(id  _Nullable json, NSError * _Nullable error) {
        NSParameterAssert(!json ^ !error);
        if (error) return callback(nil, error);
        NSParameterAssert([json isKindOfClass:[NSArray<NSDictionary *> class]]);
        NSMutableArray<WBBannerModel *> *banners = [NSMutableArray arrayWithCapacity:[(NSArray *)json count]];
        for (id bannerDict in json) {
            NSParameterAssert([bannerDict isKindOfClass:[NSDictionary class]]);
            WBBannerModel *bannerModel = [[WBBannerModel alloc] initWithDict:bannerDict sourceInterface:URL];
            [banners addObject:bannerModel];
        }
        callback(banners, nil);
    }];
}

- (void)apppage_tipsWithCount:(NSUInteger)count callback:(void (^)(NSArray<NSString *> * _Nullable, NSError * _Nullable))callback {
    NSDictionary *params = @{
        @"count": @(count),
    };
    [self POST:@"apppage/tips" params:params callback:^(id  _Nullable json, NSError * _Nullable error) {
        NSParameterAssert(!json ^ !error);
        if (error) return callback(nil, error);
        NSParameterAssert([json isKindOfClass:[NSDictionary class]]);
        int count = [json[@"count"] intValue];
        NSArray<NSString *> *list = json[@"list"];
        NSParameterAssert(count == [list count]);
        callback(list, nil);
    }];
}

@end

