+ (instancetype)sharedInstance {
    static WBBannerManager * sharedInstance = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        sharedInstance = [[self alloc] init];
    });
    return sharedInstance;
}

- (void)loadBannerDataWithCompletion:(void (^)(BOOL success))completion {
    [[WBNetworkManager defaultManager] apppage_launch:^(NSArray<WBBannerModel *> * _Nullable banners, NSError * _Nullable error) {
        dispatch_async(dispatch_get_main_queue(), ^{
            if (error || [banners count] == 0) {
                self.hasBannerData = NO;
                if (completion) {
                    completion(NO);
                }
            } else {
                self.hasBannerData = YES;
                self.bannerArray = banners;
                if (completion) {
                    completion(YES);
                }
            }
        });
    }];
}

