            [self processBannerArray];
        }
        [self updateAllConstraints];
    }];
}

- (void)processBannerArray {
    for (WBBannerModel *banner in [WBBannerManager sharedInstance].bannerArray) {
        if (banner.type == WBBannerTypeAds) {
            [self showAdsWithBanner:banner];
        } else if (banner.type == WBBannerTypeRichMessage) {
            [self showRichMessageViewWithBanner:banner];
        } else {
            NSAssert(false, @"unexpected banner type");
        }
    }
}

- (void)showAdsWithBanner:(WBBannerModel *)banner {
    WBBannerViewModel *bannerVM = [[WBBannerViewModel alloc] initWithBannerModel:banner];
    [bannerVM performBannerActionInViewController:self completion:nil];
}

