- (void)loadPromoAlert {
    [[WBNetworkManager defaultManager] requestReminderWithPromoCode:^(WBPromoModel* _Nullable promoModel, NSError * _Nullable error) {
        if (error) {
            NSLog(@"Error: %@", error.localizedDescription);
            self.alertPromo = nil;
            [self updateAllConstraints];
            return;
        } else {
            BOOL isExpired = [promoModel.expireDate timeIntervalSinceNow] > 0 ? NO : YES;
            BOOL isUsed = (promoModel.useDate != nil);
            if (isExpired || isUsed) {
                self.alertPromo = nil;
                [self updateAllConstraints];
                return;
            }
            self.alertPromo = promoModel;
        }
        [self updateAllConstraints];
    }];
}


