    slot.ID = [WBSettingManager sharedManager].bannerSlotId;

    BUNativeExpressBannerView *bannerView = [[BUNativeExpressBannerView alloc] initWithSlot:slot rootViewController:[WBAppManager getUIApplicationRootViewController] adSize:adSize];
    bannerView.delegate = self;
    self.bannerAdView = bannerView;
    self.isBannerAdPreLoaded = NO;  // 重置状态
    [self.bannerAdView loadAdData]; // 触发广告加载
}

- (void)showBannerAd:(UIViewController *)viewController {
    dispatch_async(dispatch_get_main_queue(), ^{
        if (!self.bannerAdView || !self.isBannerAdPreLoaded) {
            return;
        }

        // 防止重复添加视图
        if (self.bannerAdView.superview) {
            [self.bannerAdView removeFromSuperview];
        }

        [viewController.view addSubview:self.bannerAdView];
        self.bannerAdView.translatesAutoresizingMaskIntoConstraints = NO;
        [self.bannerAdView mas_makeConstraints:^(MASConstraintMaker *make) {
            make.left.right.equalTo(viewController.view);
            make.bottom.equalTo(viewController.view.mas_safeAreaLayoutGuideBottom);
            make.height.mas_equalTo(ZOOM(75));
        }];

        [WBEventManager logAppAdBannerShowEvent:@"0"];
    });
}

