// 检查当前视图控制器是否包含活跃的广告视图
- (BOOL)hasActiveAdViews {
    WBGroMoreAdManager *adManager = [WBGroMoreAdManager sharedManager];

    // 检查Banner广告：判断当前控制器是否正在展示banner，且banner视图有效
    if (adManager.bannerAdView && adManager.bannerAdView.superview == self.view) {
        return YES;
    }

    // 检查信息流广告：遍历nativeAdDataArray，检查是否有广告视图添加到当前控制器
    for (BUNativeAd *nativeAd in adManager.nativeAdDataArray) {
        if (nativeAd.mediation.canvasView && nativeAd.mediation.canvasView.superview == self.view) {
            return YES;
        }
    }

    // 检查广告管理器是否标记了当前控制器有预加载的广告
    if (adManager.vappLaunchVC == self) {
        return YES;
    }

    return NO;
}


