@property (nonatomic, strong) WBGroInterstitialAdViewController *interstitialAdVC;
@property (nonatomic, strong) BUNativeAdsManager *nativeAdManager;
@property (nonatomic, assign) NSInteger nativeAdRetryCount;
@property (nonatomic, assign) NSInteger maxNativeAdRetryCount;
