- (instancetype)init {
    self = [super init];
    if (self) {
        self.originVC = nil;
        self.observerTokens = [NSMutableArray array];

        // 添加对 "常规弹窗关闭" 观察者
        [self.observerTokens addObject:[[NSNotificationCenter defaultCenter] addObserverForName:WBPopupDismissNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(POPUP_DELAY * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                [self handlePopupDismissal];
            });
        }]];

        // 添加对 "静态弹窗关闭" 观察者（图片弹窗）
        [self.observerTokens addObject:[[NSNotificationCenter defaultCenter] addObserverForName:CustomPopupDismissedNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(POPUP_DELAY * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                [self handlePopupDismissal];
            });
        }]];

        // 添加对 "动态弹窗关闭" 观察者（动画弹窗）
        [self.observerTokens addObject:[[NSNotificationCenter defaultCenter] addObserverForName:DynamicPopupDismissedNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(POPUP_DELAY * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                [self handlePopupDismissal];
            });
        }]];

        // 添加对 "静态弹窗领取优惠券" 和 "动态弹窗领取优惠券" 观察者
        [self.observerTokens addObject:[[NSNotificationCenter defaultCenter] addObserverForName:WBStaticPromoReceiveNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            self.whichTogetPromo = @"static";
        }]];

        [self.observerTokens addObject:[[NSNotificationCenter defaultCenter] addObserverForName:WBDynamicPromoReceiveNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            self.whichTogetPromo = @"dynamic";
        }]];

        // 添加对 "会员中心关闭" 的观察者
        [self.observerTokens addObject:[[NSNotificationCenter defaultCenter] addObserverForName:WBVipReturnNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(POPUP_DELAY * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                [self handlePopupQueueLeft];
            });
        }]];

        // 添加对 "登录/注册界面关闭" 的观察者
        [self.observerTokens addObject:[[NSNotificationCenter defaultCenter] addObserverForName:WBLoginReturnNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(POPUP_DELAY * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                [self handlePopupQueueLeft];
            });
        }]];

        // 添加对 "优惠券界面关闭" 的观察者
        [self.observerTokens addObject:[[NSNotificationCenter defaultCenter] addObserverForName:WBPromoReturnNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(POPUP_DELAY * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                [self handlePopupQueueLeft];
            });
        }]];
    }
    return self;
}

- (void)dealloc {
    // 移除观察者
    if (self.observerTokens) {
        for (id observerToken in self.observerTokens) {
            [[NSNotificationCenter defaultCenter] removeObserver:observerToken];
        }
        self.observerTokens = nil;
    }
}


#pragma mark - route

- (void)jun_routeBuild:(JUNRouteBuilder *)route {

    [route name:@"popup" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        if (userInfo[@"data"]) {
            NSDictionary *richMessagesData = [userInfo[@"data"] jsonValueDecoded];
            self.sourceInterface = userInfo[@"sourceInterface"];
            NSLog(@"richMessagesData = %@", richMessagesData);
            if (richMessagesData && [richMessagesData count] > 0) { // 检查 richMessagesData 是否非空且包含键值对
                WBPopupShowStatus status = [[WBPopupDecisionMaker sharedInstance] shouldShowPopup];
                switch (status) {
                    case WBPopupShowStatusShow:
                        // 正常展示弹窗
                        [self handleRichMessages:richMessagesData];
                        break;
                    case WBPopupShowStatusNotShow:
                        // 不展示弹窗，直接跳过
                        break;
                    case WBPopupShowStatusStore:
                        // 暂存弹窗数据，待相关事件（如开屏广告）结束后展示
                        [self storePopupDataForLater:richMessagesData];
                        break;
                    default:
                        break;
                }
            } else {
                // 如果 richMessagesData 为空，则不处理
                NSLog(@"route_popup: richMessagesData is empty, no popup will be shown.");
            }
            self.sourceInterface = nil;
        }
        next(nil);
    }];

    [route name:@"promoReceive" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        NSString *promocodeId = userInfo[@"promocodeId"];
        NSLog(@"promocodeId = %@", promocodeId);

        if ([self.whichTogetPromo isEqual:@"static"]) {
            [WBCustomPopupViewController handlePromoReceiveWithPromoId:promocodeId];
        } else if ([self.whichTogetPromo isEqual:@"dynamic"]) {
            [WBDynamicPopupViewController handlePromoReceiveWithPromoId:promocodeId];
        }

        next(nil);
    }];

    [route name:@"rate" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        self.stashedDefaultHandler = nil;
        NSString *type = userInfo[@"type"];
        if (type && [type isEqualToString:@"inapp"]) {
            if (@available(iOS 14.0, *)) {
                UIWindowScene *scene = (UIWindowScene *)[UIApplication sharedApplication].connectedScenes.allObjects[0];
                [WBEventManager logAppQuickRateEvent:[@(WBSettingManager.sharedManager.TrackId) stringValue] from:@"route"];
                [SKStoreReviewController requestReviewInScene:scene];
            }
            return;
        }
        [[WBAppManager sharedManager] writeReviewInAppStore:@"route"];
    }];

    [route name:@"closeVip" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        [[NSNotificationCenter defaultCenter] postNotificationName:WBRouteCloseVIPNotification object:nil];
    }];

    [route name:@"exit" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        exit(0);
    }];

    [route name:@"appleShare" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        // pull share page
        [WBMineViewController shareApp];
    }];

    [route name:@"eventShareAppByWeChatFriends" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        [[WBAppManager sharedManager] shareAppByWeChatFriends];
